```go
func (m *Manifest) RemoveLayers() error {
    // 1. Get all manifests
    ms, err := Manifests(true)

    // 2. Build set of digests still in use by other manifests
    inUse := make(map[string]struct{})
    for _, other := range ms {
        for _, layer := range append(other.Layers, other.Config) {
            if layer.Digest != "" {
                inUse[layer.Digest] = struct{}{}
            }
        }
    }

    // 3. Remove layers not used by any other manifest
    for _, layer := range append(m.Layers, m.Config) {
        if layer.Digest == "" || used := inUse[layer.Digest]; used {
            continue
        }
        blob, err := BlobsPath(layer.Digest)
        if err := os.Remove(blob); err != nil {
            return err
        }
    }
}
```

**Key Insight:** Delete is a two-step process:
1. Remove the manifest file
2. Remove any layers that are no longer referenced by other manifests

